export default function Experience() {
  const svgRef = useRef(null);
  const pathRef = useRef(null);
  const frameRef = useRef(null);
  const [dims, setDims] = useState({ w: 1200, h: 800 });

  useEffect(() => {
    const el = svgRef.current;
    if (!el) return undefined;

    const resizeObserver = new ResizeObserver((entries) => {
      const entry = entries[0];
      if (!entry) return;
      setDims({
        w: entry.contentRect.width,
        h: entry.contentRect.height,
      });
    });

    resizeObserver.observe(el);
    const rect = el.getBoundingClientRect();
    setDims({ w: rect.width, h: rect.height });

    return () => {
      resizeObserver.disconnect();
    };
  }, []);

  const x1 = dims.w * 0.28;
  const y1 = dims.h * 0.45;
  const x2 = dims.w * 0.72;
  const y2 = dims.h * 0.68;
  const cp1x = dims.w * 0.35;
  const cp1y = dims.h * 0.78;
  const cp2x = dims.w * 0.65;
  const cp2y = dims.h * 0.3;
  const pathD = `M ${x1} ${y1} C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${x2} ${y2}`;
  const mid = getBezierPoint(0.5, x1, y1, cp1x, cp1y, cp2x, cp2y, x2, y2);

  useEffect(() => {
    const pathEl = pathRef.current;
    if (!pathEl) return undefined;

    const length = pathEl.getTotalLength();
    pathEl.style.transition = "none";
    pathEl.style.strokeDasharray = `${length}`;
    pathEl.style.strokeDashoffset = `${length}`;

    frameRef.current = requestAnimationFrame(() => {
      pathEl.style.transition = "stroke-dashoffset 1.8s cubic-bezier(0.4,0,0.2,1) 0.5s";
      pathEl.style.strokeDashoffset = "0";
    });

    return () => {
      if (frameRef.current) {
        cancelAnimationFrame(frameRef.current);
      }
    };
  }, [pathD]);

  return (
    <section className="experience-page">
