            </filter>
            <linearGradient id="path-gradient" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor="#4361ee" stopOpacity="0.9" />
              <stop offset="50%" stopColor="#7b5ea7" stopOpacity="0.7" />
              <stop offset="100%" stopColor="#f72585" stopOpacity="0.9" />
            </linearGradient>
            <linearGradient id="path-gradient-dim" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor="#4361ee" stopOpacity="0.15" />
              <stop offset="100%" stopColor="#f72585" stopOpacity="0.15" />
            </linearGradient>
          </defs>

          <path d={pathD} stroke="url(#path-gradient-dim)" strokeWidth="24" fill="none" filter="url(#path-glow)" />
          <path d={pathD} stroke="url(#path-gradient)" strokeWidth="1.5" fill="none" strokeOpacity="0.35" />
          <path
            ref={pathRef}
            d={pathD}
            stroke="url(#path-gradient)"
            strokeWidth="1.5"
            fill="none"
            strokeLinecap="round"
            filter="url(#path-glow)"
          />

          <circle cx={x1} cy={y1} r="5" fill={CLIENTS[0].color} filter="url(#path-glow)" opacity="0.9">
            <animate attributeName="r" values="4;6;4" dur="3s" repeatCount="indefinite" />
            <animate attributeName="opacity" values="0.9;0.5;0.9" dur="3s" repeatCount="indefinite" />
          </circle>
          <circle cx={x1} cy={y1} r="10" fill="none" stroke={CLIENTS[0].color} strokeWidth="1" opacity="0.3">
            <animate attributeName="r" values="8;14;8" dur="3s" repeatCount="indefinite" />
            <animate attributeName="opacity" values="0.3;0;0.3" dur="3s" repeatCount="indefinite" />
          </circle>

          <circle cx={x2} cy={y2} r="5" fill={CLIENTS[1].color} filter="url(#path-glow)" opacity="0.9">
            <animate attributeName="r" values="4;6;4" dur="3s" repeatCount="indefinite" />
            <animate attributeName="opacity" values="0.9;0.5;0.9" dur="3s" repeatCount="indefinite" />
          </circle>
          <circle cx={x2} cy={y2} r="10" fill="none" stroke={CLIENTS[1].color} strokeWidth="1" opacity="0.3">
